// Filter to actual rows (Postgres can return [{}] when 0 rows).
// One item per due escalation; downstream HTTP fans out automatically.
// $env.MIKAEL_ALERT_PHONE — if missing, skip everything (defensive).
const phone = $env.MIKAEL_ALERT_PHONE;
if (!phone) return [];
const items = $input.all();
const out = [];
for (const it of items) {
  const r = it.json;
  if (!r || !r.escalation_id) continue;
  const minutesPending = Math.round(Number(r.minutes_pending || 30));
  const detail = String(r.alert_detail || r.last_detail || '').slice(0, 240);
  out.push({ json: {
    to_number: phone,
    escalation_id: r.escalation_id,
    check_id: r.check_id,
    check_name: r.check_name || r.check_id,
    criticality: r.criticality || 'high',
    from_status: r.from_status || 'unknown',
    to_status: r.to_status || r.last_status || 'critical',
    detail,
    minutes_pending: String(minutesPending),
  }});
}
return out;
